const __pageData = JSON.parse('{"title":"契约测试：跨服务边界的验证","description":"深入契约测试的形式化定义与工程实践，涵盖Consumer-Driven与Provider-Driven契约模型、Pact JS实现、Pact Broker版本管理以及CI/CD中的契约门禁策略。","frontmatter":{"title":"契约测试：跨服务边界的验证","description":"深入契约测试的形式化定义与工程实践，涵盖Consumer-Driven与Provider-Driven契约模型、Pact JS实现、Pact Broker版本管理以及CI/CD中的契约门禁策略。","date":"2026-05-01T00:00:00.000Z","tags":["测试工程","契约测试","Pact","微服务","Consumer-Driven Contract","API测试"],"category":"engineering"},"headers":[],"relativePath":"testing-engineering/13-contract-testing.md","filePath":"testing-engineering/13-contract-testing.md","lastUpdated":1777741461000}');
